class Solution:
    def getAverages(self, nums, k):
        n = len(nums)
        res = [-1] * n
        for i in range(n):
            if i - k < 0 or i + k >= n:
                continue
            total = 0
            for j in range(i - k, i + k + 1):
                total += nums[j]
            res[i] = total // (2 * k + 1)
        return res

